%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%  LOCAL FUNCTIONS
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
function f = objective(xr, PB)
xh = decode(xr, PB);
f  = PB.core(xh);
end

function xh = decode(xr, PB)
if ~iscell(xr) || numel(xr) ~= 2
    error('becker_lago_k29_2D: xr must be a cell array with exactly 2 entries.');
end
xh = zeros(2,1);
tmp = check_C(xr{1}, PB.lb_C_work(1), PB.ub_C_work(1), 'x1');
xh(1) = map_C_to_orig(tmp, PB.lb_C_work(1), PB.ub_C_work(1), PB.lb_orig(1), PB.ub_orig(1));
xh(2) = check_K(xr{2}, PB.K2_labels, PB.K2_embed, 'x2');
end

function v = check_C(val, a, b, name)
if ~isnumeric(val) || ~isscalar(val) || ~isreal(val)
    error('becker_lago_k29_2D: %s must be a real scalar.', name);
end
if val < a || val > b
    error('becker_lago_k29_2D: %s=%g outside [%g,%g].', name, val, a, b);
end
v = double(val);
end

function xorig = map_C_to_orig(xwork, lbw, ubw, lbo, ubo)
if abs(ubw - lbw) <= 1e-14
    t = 0;
else
    t = (xwork - lbw) / (ubw - lbw);
end
t = max(0, min(1, t));
xorig = lbo + t * (ubo - lbo);
end

function v = check_D(val, grid, name)
if ~isnumeric(val) || ~isscalar(val) || ~isreal(val)
    error('becker_lago_k29_2D: %s must be a real scalar.', name);
end
grid = grid(:);
[dmin, idx] = min(abs(grid - val));
if dmin > 1e-10 * max(1, max(abs(grid)))
    error('becker_lago_k29_2D: %s=%g not in grid.', name, val);
end
v = grid(idx);
end

function v = check_K(label, labels, embed, name)
if isstring(label), label = char(label); end
if ~(ischar(label) && isrow(label))
    error('becker_lago_k29_2D: %s must be a char vector.', name);
end
idx = find(strcmp(label, labels), 1);
if isempty(idx)
    error('becker_lago_k29_2D: %s unknown label ''%s''.', name, label);
end
v = embed(idx);
end



% -------------------------------------------------------------------------
% Embedded original continuous problem (verbatim; only the top-level name is renamed)
% -------------------------------------------------------------------------
function [f] = becker_lago_orig(x)
%
% Purpose:
%
%    Function becker_lago is the function described in
%    Montaz et al. (2005).
%
%    dim = 2
%    Minimum global value = 0
%    Global minima = [-5 -5]', [-5 5]', [5 -5]', [5 5]'
%    Local minima 
%    Search domain: -10 <= x <= 10 (Montaz et al. (2005))
%
% Input:  
%
%         x (point given by the optimizer).
%
% Output: 
%
%         f (function value at x).
%
% Written by A. L. Custodio and J. F. A. Madeira.
%
% Version June 2012.
%
%
f = (abs(x(1))-5)^2+(abs(x(2))-5)^2;
end
%
% End of becker_lago.

